import React from 'react';

export default function ProgressStepper({ steps, currentStep = 0 }) {
  return (
    <div className="w-full max-w-xl mx-auto py-10 font-sans">
      <div className="flex items-center justify-between relative">
        {/* Track Line Background */}
        <div className="absolute top-1/2 left-0 right-0 h-1 bg-gray-200 -translate-y-1/2 -z-10" />

        {/* Dynamic active line width */}
        <div
          className="absolute top-1/2 left-0 h-1 bg-purple-500 -translate-y-1/2 -z-10 transition-all duration-500"
          style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}
        />

        {/* Step Nodes */}
        {steps.map((step, idx) => {
          const isCompleted = idx < currentStep;
          const isActive = idx === currentStep;

          return (
            <div key={idx} className="flex flex-col items-center relative">
              <div
                className={`w-10 h-10 rounded-full flex items-center justify-center border-2 font-semibold text-sm transition-all duration-300 ${
                  isCompleted
                    ? 'bg-purple-600 border-purple-600 text-white'
                    : isActive
                    ? 'bg-white border-purple-600 text-purple-600 ring-4 ring-purple-100'
                    : 'bg-white border-gray-300 text-gray-400'
                }`}
              >
                {isCompleted ? (
                  <svg className="w-5 h-5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                  </svg>
                ) : (
                  idx + 1
                )}
              </div>
              <span className={`absolute top-12 text-xs font-bold whitespace-nowrap ${
                isActive ? 'text-purple-600' : 'text-gray-400'
              }`}>
                {step.label}
              </span>
            </div>
          );
        })}
      </div>
    </div>
  );
}
